+        var buf: [8192]u8 = undefined;
+        while (true) {
+            const n = req.read(&buf) catch return PyPIError.NetworkError;
+            if (n == 0) break;
+            body_list.appendSlice(self.allocator, buf[0..n]) catch return PyPIError.OutOfMemory;
