+/// Platform specification
+pub const Platform = struct {
+    os: OS,
+    arch: Arch,
+    python_major: u8 = 3,
+    python_minor: u8 = 11,
+    glibc_version: ?struct { major: u8, minor: u8 } = null,
+    macos_version: ?struct { major: u8, minor: u8 } = null,
