+            .linux => .linux,
+            .macos => .macos,
+            .windows => .windows,
+            else => .unknown,
+        };
+
+        const arch: Arch = switch (target.cpu.arch) {
+            .x86_64 => .x86_64,
+            .aarch64 => .aarch64,
+            .arm => .arm,
+            .x86 => .i686,
+            else => .unknown,
